 if sys=='E20A_PRIMARY_REFERENCE': return fam not in ['ADVERSARIAL_FALSE_ALIGNMENT','CROSS_MODAL_NECESSITY','CONTRADICTORY_MODALITY_REPAIR','NOISY_STREAM_REPAIR']
